import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Installing Java on Windows","description":"A step-by-step guide on how to install Java on Windows.","frontmatter":{"title":"Installing Java on Windows","description":"A step-by-step guide on how to install Java on Windows.","authors":["IMB11","skycatminepokie"],"next":false,"files":[]},"headers":[],"relativePath":"players/installing-java/windows.md","filePath":"players/installing-java/windows.md","lastUpdated":1768523109000}`);var l={name:`players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Java on Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Java on Windows”">​</a></h1><p>This guide will walk you through installing Java 21 on Windows.</p><p>The Minecraft Launcher comes with its own Java installation, so this section is only relevant if you want to use the Fabric <code>.jar</code> based installer, or if you want to use the Minecraft Server <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Check if Java Is Already Installed <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Check if Java Is Already Installed”">​</a></h2><p>To check if Java is already installed, you must first open the command prompt.</p><p>You can do this by pressing <kbd>Windows</kbd>+<kbd>R</kbd> and typing <code>cmd.exe</code> into the box that appears.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows Run Dialog with &quot;cmd.exe&quot; in the run bar" loading="lazy"></p><p>Once you have opened the command prompt, type <code>java -version</code> and press <kbd>Enter</kbd>.</p><p>If the command runs successfully, you will see something like this. If the command failed, proceed to the next step.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Command prompt with &quot;java -version&quot; typed in" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>To use Minecraft 1.21.11, you&#39;ll need at least Java 21 installed.</p><p>If this command displays any version lower than 21, you&#39;ll need to update your existing Java installation; keep reading this page.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Download the Java 21 Installer <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Download the Java 21 Installer”">​</a></h2><p>To install Java 21, you&#39;ll need to download the installer from <a href="https://adoptium.net/temurin/releases?version=21&amp;os=windows&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>You&#39;ll want to download the <code>Windows Installer (.msi)</code> version:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium download page with Windows Installer (.msi) highlighted" loading="lazy"></p><p>You should choose <code>x86</code> if you have a 32-bit operating system, or <code>x64</code> if you have a 64-bit operating system.</p><p>The majority of modern computers will have a 64-bit operating system. If you are unsure, try using the 64-bit download.</p><h2 id="3-run-the-installer" tabindex="-1">3. Run the Installer! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Run the Installer!”">​</a></h2><p>Follow the steps in the installer to install Java 21. When you reach this page, you should set the following features to &quot;Entire feature will be installed on local hard drive&quot;:</p><ul><li><code>Set JAVA_HOME environment variable</code> - This will be added to your PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Java 21 installer with &quot;Set JAVA_HOME variable&quot; and &quot;JavaSoft (Oracle) registry keys&quot; highlighted" loading="lazy"></p><p>Once you&#39;ve done that, you can click <code>Next</code> and continue with the installation.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Windows won&#39;t always tell other programs that Java is installed until you restart your computer.</p><p><strong>Make sure to restart your computer before continuing!</strong></p></div><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Verify That Java 21 Is Installed <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Verify That Java 21 Is Installed”">​</a></h2><p>Once the installation is complete, you can verify that Java 21 is installed by opening the command prompt again and typing <code>java -version</code>.</p><p>If the command runs successfully, you will see something like shown before, where the Java version is displayed:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Command prompt with &quot;java -version&quot; typed in" loading="lazy"></p><p>If you encounter any issues, feel free to ask for help in the <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};